import React from 'react';

function BookCard({ book, onSelectBook }) {
  const getGradientByRating = (rating) => {
    if (rating >= 4.5) return 'from-emerald-400 to-teal-500';
    if (rating >= 4.0) return 'from-blue-400 to-indigo-500';
    if (rating >= 3.5) return 'from-purple-400 to-pink-500';
    return 'from-orange-400 to-red-500';
  };

  const getRatingColor = (rating) => {
    if (rating >= 4.5) return 'text-emerald-600';
    if (rating >= 4.0) return 'text-blue-600';
    if (rating >= 3.5) return 'text-purple-600';
    return 'text-orange-600';
  };

  return (
    <div
      onClick={() => onSelectBook(book.id)}
      className="group relative bg-white rounded-2xl shadow-lg hover:shadow-2xl cursor-pointer transform transition-all duration-500 hover:-translate-y-2 overflow-hidden border border-gray-100"
    >
      {/* Gradient top border */}
      <div className={`absolute top-0 left-0 right-0 h-1 bg-gradient-to-r ${getGradientByRating(book.rating)}`}></div>

      {/* Card content */}
      <div className="p-5 lg:p-6">
        {/* Book icon */}
        <div className="flex items-center justify-between mb-4 lg:mb-6">
          <div className={`w-10 h-10 lg:w-12 lg:h-12 rounded-xl bg-gradient-to-r ${getGradientByRating(book.rating)} flex items-center justify-center shadow-lg group-hover:scale-110 transition-transform duration-300`}>
            <span className="text-white text-lg lg:text-xl font-bold">📖</span>
          </div>
          <div className="flex items-center space-x-1">
            {[...Array(5)].map((_, i) => (
              <span 
                key={i} 
                className={`text-lg ${
                  i < Math.floor(book.rating) 
                    ? 'text-yellow-400' 
                    : i < book.rating 
                    ? 'text-yellow-300' 
                    : 'text-gray-200'
                }`}
              >
                ⭐
              </span>
            ))}
          </div>
        </div>

        {/* Book title */}
        <h3 className="text-lg lg:text-xl font-bold text-gray-900 mb-2 lg:mb-3 line-clamp-2 group-hover:text-indigo-600 transition-colors duration-300">
          {book.title}
        </h3>

        {/* Author */}
        <p className="text-sm lg:text-base text-gray-600 mb-3 lg:mb-4 font-medium">
          by <span className="text-gray-800">{book.author}</span>
        </p>

        {/* Rating and reviews */}
        <div className="flex items-center justify-between">
          <div className="flex items-center space-x-2">
            <span className={`text-xl lg:text-2xl font-bold ${getRatingColor(book.rating)}`}>
              {book.rating}
            </span>
            <span className="text-xs lg:text-sm text-gray-500">rating</span>
          </div>
          <div className="text-xs lg:text-sm text-gray-500">
            {book.reviews.length} review{book.reviews.length !== 1 ? 's' : ''}
          </div>
        </div>

        {/* Hover indicator */}
        <div className="mt-4 lg:mt-6 flex items-center text-indigo-600 opacity-0 group-hover:opacity-100 transition-opacity duration-300">
          <span className="text-xs lg:text-sm font-medium">Read more</span>
          <svg className="w-3 h-3 lg:w-4 lg:h-4 ml-2 transform group-hover:translate-x-1 transition-transform duration-300" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
          </svg>
        </div>
      </div>

      {/* Subtle background pattern */}
      <div className="absolute top-0 right-0 w-32 h-32 opacity-5 transform rotate-12 translate-x-8 -translate-y-8">
        <div className="w-full h-full bg-gradient-to-br from-indigo-500 to-purple-600 rounded-full"></div>
      </div>
    </div>
  );
}

export default BookCard;
